  const accessStatus = applyAccessStatusNarrativeGate({ message: input.message, answer });
  stages.push({
    gate: 'access_status_narrative',
    gated: accessStatus.gated,
    state: accessStatus.gated ? 'BLOCKED' : 'READY',
    reason: accessStatus.gated
