// Commit the chat fixes via GitHub API and trigger Render deploy
const TOKEN = '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';
const OWNER = 'ibb142';
const REPO = 'rork-global-real-estate-invest';
const BRANCH = 'main';
const GH = `https://api.github.com/repos/${OWNER}/${REPO}`;
const H = { 'Authorization': `Bearer ${TOKEN}`, 'Accept': 'application/vnd.github+json', 'X-Github-Api-Version': '2022-11-28', 'User-Agent': 'ivx-deploy' };
const fs = await import('fs');

async function gh(path, method='GET', body) {
  const opts = { method, headers: H };
  if (body) opts.body = JSON.stringify(body);
  const r = await fetch(GH + path, opts);
  const t = await r.text();
  let j; try { j = JSON.parse(t); } catch { j = t; }
  if (!r.ok) { console.error(`GH ${method} ${path} -> ${r.status}:`, typeof j === 'string' ? j.slice(0,300) : j); throw new Error(`GH ${r.status}`); }
  return j;
}

// 1. Get current branch ref + latest commit SHA + tree SHA
const ref = await gh(`/git/ref/heads/${BRANCH}`);
const parentSha = ref.object.sha;
console.log('parent commit:', parentSha);
const parentCommit = await gh(`/git/commits/${parentSha}`);
const baseTree = parentCommit.tree.sha;
console.log('base tree:', baseTree);

// 2. Create blobs for changed files
const files = [
  { path: 'backend/public-chat-ai.ts', content: fs.readFileSync('backend/public-chat-ai.ts', 'utf8') },
  { path: 'expo/app/chat-hub.tsx', content: fs.readFileSync('expo/app/chat-hub.tsx', 'utf8') },
];
const treeEntries = [];
for (const f of files) {
  const blob = await gh('/git/blobs', 'POST', { content: f.content, encoding: 'utf-8' });
  console.log('blob', f.path, '->', blob.sha.slice(0,10));
  treeEntries.push({ path: f.path, mode: '100644', type: 'blob', sha: blob.sha });
}

// 3. Create tree
const tree = await gh('/git/trees', 'POST', { base_tree: baseTree, tree: treeEntries });
console.log('new tree:', tree.sha);

// 4. Create commit
const commit = await gh('/git/commits', 'POST', {
  message: 'fix(chat): stop false-positive BLOCKED on investor questions + fix disappearing chat race\n\n- public-chat-ai: only run developer-evidence gate pipeline on developer/owner branches, not general_ai investor questions. Normal words like "verified" (KYC) or "completed" (onboarding) were tripping the reliability gate and rewriting answers to STATE: BLOCKED.\n- chat-hub: guard history restoration effect with sendInFlight ref so optimistic assistant bubbles are not wiped by a refetch race (disappearing chat bug).',
  tree: tree.sha,
  parents: [parentSha],
});
console.log('new commit:', commit.sha);

// 5. Update ref
const updated = await gh(`/git/ref/heads/${BRANCH}`, 'PATCH', { sha: commit.sha });
console.log('ref updated ->', updated.object.sha.slice(0,10));

// 6. Trigger render deploy workflow (in case push trigger needs help)
const wf = await gh('/actions/workflows', 'GET');
const renderWf = wf.workflows.find(w => w.name.toLowerCase().includes('render'));
if (renderWf) {
  console.log('render workflow id:', renderWf.id);
  const trig = await gh(`/actions/workflows/${renderWf.id}/dispatches`, 'POST', { ref: BRANCH });
  console.log('workflow dispatch sent:', trig === '' ? 'OK (204)' : trig);
} else {
  console.log('no render workflow found; push will auto-trigger');
}
console.log('\nDONE. Commit:', commit.sha);
EOF
