// Watch the latest GitHub Actions render-deploy run until it completes
const TOKEN = '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';
const OWNER = 'ibb142';
const REPO = 'rork-global-real-estate-invest';
const GH = `https://api.github.com/repos/${OWNER}/${REPO}`;
const H = { 'Authorization': `Bearer ${TOKEN}`, 'Accept': 'application/vnd.github+json', 'X-Github-Api-Version': '2022-11-28', 'User-Agent': 'ivx-deploy' };

const sleep = (ms) => new Promise(r => setTimeout(r, ms));
async function gh(path) {
  const r = await fetch(GH + path, { headers: H });
  return r.json();
}

// find the latest render-deploy-trigger run
let run = null;
for (let i = 0; i < 6; i++) {
  const runs = await gh('/actions/runs?per_page=8');
  const render = runs.workflow_runs.find(r => /render/i.test(r.name) || /render/i.test(r.path));
  if (render) { run = render; break; }
  await sleep(4000);
}
if (!run) { console.log('no render run found'); process.exit(1); }
console.log('watching run:', run.id, 'status:', run.status, 'conclusion:', run.conclusion);

let final = run;
const start = Date.now();
while (Date.now() - start < 540000) {
  const cur = await gh(`/actions/runs/${run.id}`);
  final = cur;
  const elapsed = Math.round((Date.now() - start) / 1000);
  console.log(`[${elapsed}s] status=${cur.status} conclusion=${cur.conclusion ?? '-'}`);
  if (cur.status === 'completed') break;
  await sleep(12000);
}
console.log('\nFINAL status:', final.status, 'conclusion:', final.conclusion);
if (final.conclusion === 'success') {
  console.log('DEPLOY WORKFLOW SUCCEEDED.');
} else {
  console.log('DEPLOY WORKFLOW DID NOT SUCCEED — checking Render directly.');
}
EOF
